import { defineStore } from "pinia";
import { ref, computed } from "vue";

const API_BASE = "projekt_hub_pro.project_hub_pro.api.timesheet_management";

// ── helpers ──────────────────────────────────────────────────────────────────

function getCsrfToken() {
	if (window.frappe && window.frappe.csrf_token && window.frappe.csrf_token !== "None") {
		return window.frappe.csrf_token;
	}
	if (window.csrf_token && window.csrf_token !== "{{ csrf_token }}") {
		return window.csrf_token;
	}
	return "";
}

async function apiCall(method, params = {}) {
	const csrfToken = getCsrfToken();
	const formData = new FormData();
	Object.entries(params).forEach(([key, value]) => {
		if (value !== null && value !== undefined) {
			formData.append(key, value);
		}
	});

	const response = await fetch(`/api/method/${method}`, {
		method: "POST",
		headers: { "X-Frappe-CSRF-Token": csrfToken },
		body: formData,
	});

	const data = await response.json();

	if (data._server_messages && window.frappe) {
		try {
			const messages = JSON.parse(data._server_messages);
			if (Array.isArray(messages)) {
				messages.forEach((msg) => {
					try {
						const msgData = JSON.parse(msg);
						if (msgData.message) {
							frappe.show_alert({
								message: msgData.message,
								indicator: msgData.indicator || "blue",
							});
						}
					} catch {
						if (typeof msg === "string") {
							frappe.show_alert({ message: msg, indicator: "blue" });
						}
					}
				});
			}
		} catch (e) {
			console.error("Error parsing server messages:", e);
		}
	}

	if (!response.ok) {
		const errorMsg = data.exception || data._server_messages || "API Error";
		if (window.frappe) {
			frappe.show_alert({ message: errorMsg, indicator: "red" });
		}
		throw new Error(errorMsg);
	}
	return data.message;
}

function getMondayOfWeek(date = new Date()) {
	const d = new Date(date);
	const day = d.getDay();
	const diff = d.getDate() - day + (day === 0 ? -6 : 1);
	return new Date(d.setDate(diff));
}

function formatDate(date) {
	const d = new Date(date);
	return d.toISOString().split("T")[0];
}

function translate(text) {
	return typeof window !== "undefined" && typeof window.__ === "function"
		? window.__(text)
		: text;
}

// ── store ─────────────────────────────────────────────────────────────────────

export const useTimesheetManagementStore = defineStore("timesheetManagement", () => {
	// State
	const timesheets = ref([]);
	const summary = ref([]);
	const missingEmployees = ref([]);
	const employees = ref([]); // for filter dropdown
	const loading = ref(false);
	const activeView = ref("list"); // "list" | "summary" | "missing"
	const currentWeekStart = ref(getMondayOfWeek()); // Monday of current week

	// Filters
	const selectedEmployee = ref(null);
	const selectedStatus = ref(null);
	const userRoles = ref([]);

	// Computed dates based on currentWeekStart
	const startDate = computed(() => formatDate(currentWeekStart.value));
	const endDate = computed(() => {
		const end = new Date(currentWeekStart.value);
		end.setDate(end.getDate() + 4); // Friday
		return formatDate(end);
	});

	function hasManagerRole(roles = []) {
		return roles.some((r) =>
			["Project Manager", "Projects Manager", "System Manager", "Administrator"].includes(r)
		);
	}

	// Computed
	const isManager = computed(() => {
		if (typeof window === "undefined" || !window.frappe) return true;
		return hasManagerRole(userRoles.value);
	});

	// Actions
	async function loadUserRoles() {
		if (typeof window === "undefined" || !window.frappe) {
			userRoles.value = [];
			return;
		}

		let roles = window.frappe.user_roles || window.frappe.boot?.user?.roles || [];

		// In website SPA routes, roles are often not preloaded.
		if (!roles.length) {
			try {
				const userRes = await fetch("/api/method/frappe.auth.get_logged_user", {
					headers: { Accept: "application/json" },
				});
				const userData = await userRes.json();
				const uid = userData.message;
				if (uid && uid !== "Guest") {
					const rolesRes = await fetch(
						`/api/method/frappe.core.doctype.user.user.get_roles?uid=${encodeURIComponent(
							uid
						)}`,
						{ headers: { Accept: "application/json" } }
					);
					const rolesData = await rolesRes.json();
					roles = rolesData.message || [];
				}
			} catch (e) {
				console.error("Failed to load user roles:", e);
			}
		}

		userRoles.value = Array.isArray(roles) ? roles : [];
	}

	async function fetchTimesheets(manageLoading = true) {
		if (manageLoading) loading.value = true;
		try {
			const params = { start_date: startDate.value, end_date: endDate.value };
			if (selectedEmployee.value) params.employee = selectedEmployee.value;
			if (selectedStatus.value) params.status = selectedStatus.value;
			timesheets.value = await apiCall(`${API_BASE}.get_timesheets`, params);
		} finally {
			if (manageLoading) loading.value = false;
		}
	}

	async function fetchSummary(manageLoading = true) {
		if (manageLoading) loading.value = true;
		try {
			const params = { start_date: startDate.value, end_date: endDate.value };
			if (selectedEmployee.value) params.employee = selectedEmployee.value;
			summary.value = await apiCall(`${API_BASE}.get_timesheet_summary`, params);
		} finally {
			if (manageLoading) loading.value = false;
		}
	}

	async function fetchMissing(manageLoading = true) {
		if (manageLoading) loading.value = true;
		try {
			missingEmployees.value = await apiCall(`${API_BASE}.get_missing_timesheets`, {
				start_date: startDate.value,
				end_date: endDate.value,
			});
		} finally {
			if (manageLoading) loading.value = false;
		}
	}

	async function fetchEmployees() {
		employees.value = await apiCall(`${API_BASE}.get_active_employees`);
	}

	async function fetchAll() {
		loading.value = true;
		try {
			await Promise.all([fetchTimesheets(false), fetchSummary(false), fetchMissing(false)]);
		} finally {
			loading.value = false;
		}
	}

	async function submitTimesheet(name) {
		const result = await apiCall(`${API_BASE}.submit_timesheet`, { timesheet_name: name });
		// Update local state
		const ts = timesheets.value.find((t) => t.name === name);
		if (ts) {
			ts.status = result.status;
			ts.docstatus = result.docstatus;
		}
		await fetchSummary();
		return result;
	}

	async function setBillable(name, isBillable) {
		const result = await apiCall(`${API_BASE}.set_timesheet_billable`, {
			timesheet_name: name,
			is_billable: isBillable ? 1 : 0,
		});
		const ts = timesheets.value.find((t) => t.name === name);
		if (ts) {
			ts.total_billable_hours = result.total_billable_hours;
		}
		return result;
	}

	async function cancelTimesheet(name) {
		const result = await apiCall(`${API_BASE}.cancel_timesheet`, { timesheet_name: name });
		const ts = timesheets.value.find((t) => t.name === name);
		if (ts) {
			ts.status = result.status;
			ts.docstatus = result.docstatus;
		}
		await fetchSummary();
		return result;
	}

	function setFilter(key, value) {
		if (key === "employee") selectedEmployee.value = value || null;
		else if (key === "status") selectedStatus.value = value || null;
	}

	function navigateWeek(direction) {
		const current = new Date(currentWeekStart.value);
		if (direction === "prev") {
			current.setDate(current.getDate() - 7);
		} else if (direction === "next") {
			current.setDate(current.getDate() + 7);
		} else if (direction === "today") {
			currentWeekStart.value = getMondayOfWeek();
			fetchAll();
			return;
		}

		currentWeekStart.value = current;
		fetchAll();
	}

	return {
		// State
		timesheets,
		summary,
		missingEmployees,
		employees,
		loading,
		activeView,
		currentWeekStart,
		selectedEmployee,
		selectedStatus,
		userRoles,
		// Computed
		isManager,
		startDate,
		endDate,
		// Actions
		loadUserRoles,
		fetchTimesheets,
		fetchSummary,
		fetchMissing,
		fetchEmployees,
		fetchAll,
		submitTimesheet,
		cancelTimesheet,
		setBillable,
		setFilter,
		navigateWeek,
	};
});
