<template>
	<div class="bg-white rounded-lg border border-gray-200 p-4 mb-4">
		<!-- Week navigation -->
		<div class="flex items-center justify-between gap-2 mb-4">
			<button
				@click="store.navigateWeek('prev')"
				class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm whitespace-nowrap"
				:title="translate('Previous week')"
			>
				← <span class="hidden sm:inline">{{ translate("Previous") }}</span>
			</button>

			<div class="text-sm sm:text-base font-semibold text-center whitespace-nowrap">
				{{ weekLabel }}
			</div>

			<div class="flex items-center gap-2">
				<button
					@click="store.navigateWeek('today')"
					class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm whitespace-nowrap"
					:title="translate('Current week')"
				>
					{{ translate("Today") }}
				</button>

				<button
					@click="store.navigateWeek('next')"
					class="px-2 py-1.5 border rounded hover:bg-gray-100 text-sm whitespace-nowrap"
					:title="translate('Next week')"
				>
					<span class="hidden sm:inline">{{ translate("Next") }}</span> →
				</button>
			</div>
		</div>

		<!-- Filters row -->
		<div class="flex flex-wrap items-end gap-3 mb-3">
			<!-- Employee filter -->
			<div>
				<label class="block text-xs text-gray-500 mb-1">{{ translate("Employee") }}</label>
				<select
					:value="selectedEmployee || ''"
					@change="emitFilter('employee', $event.target.value)"
					class="border border-gray-300 rounded px-2 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500 min-w-[160px]"
				>
					<option value="">{{ translate("All employees") }}</option>
					<option v-for="emp in employees" :key="emp.name" :value="emp.name">
						{{ emp.employee_name }}
					</option>
				</select>
			</div>

			<!-- Status filter (only for list view) -->
			<div v-if="activeView === 'list'">
				<label class="block text-xs text-gray-500 mb-1">{{ translate("Status") }}</label>
				<select
					:value="selectedStatus || ''"
					@change="emitFilter('status', $event.target.value)"
					class="border border-gray-300 rounded px-2 py-1.5 text-sm focus:outline-none focus:ring-1 focus:ring-blue-500"
				>
					<option value="">{{ translate("All statuses") }}</option>
					<option value="Draft">{{ translate("Draft") }}</option>
					<option value="Submitted">{{ translate("Submitted") }}</option>
					<option value="Cancelled">{{ translate("Cancelled") }}</option>
					<option value="Billed">{{ translate("Billed") }}</option>
				</select>
			</div>

			<!-- Refresh button -->
			<button
				@click="$emit('refresh')"
				class="flex items-center gap-1.5 px-3 py-1.5 text-sm text-gray-600 border border-gray-300 rounded hover:bg-gray-50 transition-colors mt-4"
			>
				<RefreshCw class="w-3.5 h-3.5" />
				{{ translate("Refresh") }}
			</button>
		</div>

		<!-- View toggle tabs -->
		<div class="flex gap-1 border-b border-gray-100 pt-1">
			<button
				v-for="view in views"
				:key="view.key"
				@click="$emit('view-change', view.key)"
				:class="[
					'flex items-center gap-1.5 px-3 py-2 text-sm font-medium rounded-t transition-colors',
					activeView === view.key
						? 'text-blue-600 border-b-2 border-blue-600 -mb-px bg-blue-50'
						: 'text-gray-500 hover:text-gray-700 hover:bg-gray-50',
				]"
			>
				<component :is="view.icon" class="w-4 h-4" />
				{{ translate(view.label) }}
			</button>
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
import { List, BarChart2, UserX, RefreshCw } from "lucide-vue-next";
import { useTimesheetManagementStore } from "../../stores/timesheetManagementStore";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

const store = useTimesheetManagementStore();

const views = [
	{ key: "list", label: "List", icon: List },
	{ key: "summary", label: "Summary", icon: BarChart2 },
	{ key: "missing", label: "Missing Timesheets", icon: UserX },
];

defineProps({
	employees: { type: Array, default: () => [] },
	selectedEmployee: { type: String, default: null },
	selectedStatus: { type: String, default: null },
	activeView: { type: String, default: "list" },
});

const emit = defineEmits(["filter-change", "view-change", "refresh"]);

const weekLabel = computed(() => {
	if (!store.currentWeekStart) return "";

	const start = new Date(store.currentWeekStart);
	const end = new Date(start);
	end.setDate(end.getDate() + 4); // Friday

	const startStr = start.toLocaleDateString("pl-PL", { month: "long", day: "numeric" });
	const endStr = end.toLocaleDateString("pl-PL", { month: "long", day: "numeric" });

	return `${startStr} - ${endStr}`;
});

function emitFilter(key, value) {
	emit("filter-change", { [key]: value });
}
</script>
