<template>
	<div class="min-h-screen bg-gray-50 flex flex-col">
		<!-- Header -->
		<header class="bg-white border-b border-gray-200 sticky top-0 z-20">
			<div class="w-full px-4 sm:px-6 lg:px-8">
				<div class="flex items-center justify-between h-16">
					<div class="flex items-center gap-3">
						<Clock class="w-6 h-6 text-blue-600" />
						<h1 class="text-xl font-semibold text-gray-900">
							{{ translate("Timesheet Management") }}
						</h1>
					</div>
					<div class="flex items-center gap-3 sm:gap-4">
						<OutlinerNav />
					</div>
				</div>
			</div>
		</header>

		<!-- Auth check loading -->
		<div v-if="!rolesResolved" class="flex-1 flex items-center justify-center">
			<p class="text-gray-500">{{ translate("Loading...") }}</p>
		</div>

		<!-- Access denied -->
		<div v-else-if="!store.isManager" class="flex-1 flex items-center justify-center">
			<div class="text-center p-8">
				<ShieldAlert class="w-12 h-12 text-red-400 mx-auto mb-3" />
				<p class="text-gray-600">
					{{ translate("Access denied. You need Project Manager role.") }}
				</p>
			</div>
		</div>

		<!-- Page content -->
		<main v-else class="flex-1 flex flex-col w-full px-4 sm:px-6 lg:px-8 py-4 sm:py-6">
			<TimesheetManagementHeader
				:employees="store.employees"
				:selected-employee="store.selectedEmployee"
				:selected-status="store.selectedStatus"
				:active-view="store.activeView"
				@filter-change="handleFilterChange"
				@view-change="store.activeView = $event"
				@refresh="store.fetchAll()"
			/>

			<!-- List view -->
			<TimesheetList
				v-if="store.activeView === 'list'"
				:timesheets="store.timesheets"
				:loading="store.loading"
				@submit="handleSubmit"
				@cancel="handleCancel"
				@set-billable="handleSetBillable"
			/>

			<!-- Summary view -->
			<TimesheetSummaryView
				v-else-if="store.activeView === 'summary'"
				:summary="store.summary"
				:loading="store.loading"
			/>

			<!-- Missing view -->
			<MissingTimesheetsView
				v-else
				:employees="store.missingEmployees"
				:loading="store.loading"
				:start-date="store.startDate"
				:end-date="store.endDate"
			/>
		</main>

		<BackToDeskButton />
	</div>
</template>

<script setup>
import { onMounted, ref } from "vue";
import { Clock, ShieldAlert } from "lucide-vue-next";
import { useTimesheetManagementStore } from "../stores/timesheetManagementStore";
import TimesheetManagementHeader from "../components/timesheet-management/TimesheetManagementHeader.vue";
import TimesheetList from "../components/timesheet-management/TimesheetList.vue";
import TimesheetSummaryView from "../components/timesheet-management/TimesheetSummaryView.vue";
import MissingTimesheetsView from "../components/timesheet-management/MissingTimesheetsView.vue";
import OutlinerNav from "@erpnext-projekt-hub/components/OutlinerNav.vue";
import BackToDeskButton from "@erpnext-projekt-hub/components/BackToDeskButton.vue";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

const store = useTimesheetManagementStore();
const rolesResolved = ref(false);

onMounted(async () => {
	try {
		await store.loadUserRoles();
		if (store.isManager) {
			await Promise.all([store.fetchEmployees(), store.fetchAll()]);
		}
	} catch (err) {
		console.error("Failed to load timesheet data:", err);
	} finally {
		rolesResolved.value = true;
	}
});

async function handleFilterChange(filters) {
	Object.entries(filters).forEach(([key, value]) => store.setFilter(key, value));
	await store.fetchAll();
}

async function handleSubmit(name) {
	const confirmed = await confirm_action(
		translate("Submit timesheet {0}?").replace("{0}", name)
	);
	if (!confirmed) return;
	try {
		await store.submitTimesheet(name);
	} catch (err) {
		console.error("Failed to submit timesheet:", err);
	}
}

async function handleCancel(name) {
	const confirmed = await confirm_action(
		translate("Cancel timesheet {0}?").replace("{0}", name)
	);
	if (!confirmed) return;
	try {
		await store.cancelTimesheet(name);
	} catch (err) {
		console.error("Failed to cancel timesheet:", err);
	}
}

async function handleSetBillable({ name, isBillable }) {
	try {
		await store.setBillable(name, isBillable);
	} catch (err) {
		console.error("Failed to update billable status:", err);
	}
}

function confirm_action(message) {
	return new Promise((resolve) => {
		if (window.frappe) {
			frappe.confirm(
				message,
				() => resolve(true),
				() => resolve(false)
			);
		} else {
			resolve(window.confirm(message));
		}
	});
}
</script>
