<template>
	<div class="bg-white rounded-lg border border-gray-200 overflow-hidden">
		<!-- Loading skeleton -->
		<div v-if="loading" class="p-6 space-y-3">
			<div v-for="i in 5" :key="i" class="h-10 bg-gray-100 rounded animate-pulse" />
		</div>

		<!-- Empty state -->
		<div
			v-else-if="!summary.length"
			class="flex flex-col items-center justify-center py-16 text-gray-400"
		>
			<BarChart2 class="w-10 h-10 mb-2" />
			<p class="text-sm">{{ translate("No data for the selected period.") }}</p>
		</div>

		<!-- Table -->
		<div v-else class="overflow-x-auto">
			<table class="w-full text-sm">
				<thead class="bg-gray-50 border-b border-gray-200">
					<tr>
						<th
							class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Employee") }}
						</th>
						<th
							class="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Department") }}
						</th>
						<th
							class="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Timesheets") }}
						</th>
						<th
							class="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Total Hours") }}
						</th>
						<th
							class="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wide"
						>
							{{ translate("Submitted Hours") }}
						</th>
					</tr>
				</thead>
				<tbody class="divide-y divide-gray-100">
					<tr v-for="row in summary" :key="row.employee" class="hover:bg-gray-50">
						<td class="px-4 py-3">
							<div class="font-medium text-gray-900">{{ row.employee_name }}</div>
							<div class="text-xs text-gray-400">{{ row.employee }}</div>
						</td>
						<td class="px-4 py-3 text-gray-600">{{ row.department || "—" }}</td>
						<td class="px-4 py-3 text-right text-gray-700">
							{{ row.timesheet_count }}
						</td>
						<td class="px-4 py-3 text-right font-mono font-medium text-gray-900">
							{{ (Number(row.total_hours) || 0).toFixed(1) }}h
						</td>
						<td class="px-4 py-3 text-right">
							<span
								:class="
									(Number(row.submitted_hours) || 0) > 0
										? 'text-green-700 font-medium'
										: 'text-gray-400'
								"
							>
								{{ (Number(row.submitted_hours) || 0).toFixed(1) }}h
							</span>
						</td>
					</tr>
				</tbody>
				<tfoot class="bg-gray-50 border-t border-gray-200">
					<tr>
						<td
							colspan="3"
							class="px-4 py-2 text-xs font-medium text-gray-500 text-right"
						>
							{{ translate("Total") }}
						</td>
						<td class="px-4 py-2 text-right font-mono font-bold text-gray-900">
							{{ grandTotal.toFixed(1) }}h
						</td>
						<td class="px-4 py-2 text-right font-mono font-bold text-green-700">
							{{ submittedTotal.toFixed(1) }}h
						</td>
					</tr>
				</tfoot>
			</table>
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
import { BarChart2 } from "lucide-vue-next";

const realWindow = typeof globalThis !== "undefined" ? globalThis.window : undefined;
const translate = (text) => {
	return typeof realWindow !== "undefined" && typeof realWindow.__ === "function"
		? realWindow.__(text)
		: text;
};

const props = defineProps({
	summary: { type: Array, default: () => [] },
	loading: { type: Boolean, default: false },
});

const grandTotal = computed(() => props.summary.reduce((s, r) => s + (r.total_hours || 0), 0));
const submittedTotal = computed(() =>
	props.summary.reduce((s, r) => s + (r.submitted_hours || 0), 0)
);
</script>
